	if chunk.Resource.IsSetTotalParts() && chunk.Resource.GetTotalParts() > 1 {
		// 分片场景：通过 report_id + stress_id 查找所有分片，按 part_index 排序合并
		return s.getMultiPartChunkData(ctx, chunk, chunkID)
	}

	// 4. 非分片：直接解压
