// getMultiPartChunkData 处理分片 chunk 的合并读取
// 通过 report_id + stress_id 查找同一 case 的所有分片，按 part_index 排序后合并
func (s *ReportHandler) getMultiPartChunkData(ctx context.Context, firstChunk *repo.ChunkDocument, cacheKey string) (chunkDataWithInfo, error) {
	reportID := firstChunk.Resource.GetReportID()
	stressID := firstChunk.Resource.GetStressID()
	totalParts := int(firstChunk.Resource.GetTotalParts())

	logger.Info("loading multi-part chunk: report_id=%s, stress_id=%s, total_parts=%d", reportID, stressID, totalParts)

	// 查询同一 report_id + stress_id 的所有 chunk parts
	allPartsQuery := &baseV1.QueryRequest{
		Page:     1,
		PageSize: int64(totalParts + 5), // 留余量
		Query:    fmt.Sprintf(`{"report_id":"%s","stress_id":"%s","total_parts":{"$exists":true}}`, reportID, stressID),
	}
	chunkDocs, _, err := s.reportRepo.ListChunk(ctx, allPartsQuery)
	if err != nil {
		return chunkDataWithInfo{}, fmt.Errorf("查询分片 chunk 列表失败: %v", err)
	}
	if len(chunkDocs) < totalParts {
		return chunkDataWithInfo{}, fmt.Errorf("分片 chunk 不完整: 期望 %d 个, 找到 %d 个", totalParts, len(chunkDocs))
	}

	// 按 part_index 排序
	sortedParts := make([]*repo.ChunkDocument, totalParts)
	for _, doc := range chunkDocs {
		idx := int(doc.Resource.GetPartIndex())
		if idx >= 0 && idx < totalParts {
			sortedParts[idx] = doc
		}
	}

	// 拼接 compressed_data
	var allCompressedData []byte
	for i, part := range sortedParts {
		if part == nil {
			return chunkDataWithInfo{}, fmt.Errorf("分片 chunk 缺少 part %d", i)
		}
		allCompressedData = append(allCompressedData, part.Resource.GetCompressedData()...)
	}

	logger.Info("multi-part chunk assembled: %d bytes from %d parts", len(allCompressedData), totalParts)

	// 解压
	decompressedData, err := utils.Decompress(allCompressedData)
	if err != nil {
		return chunkDataWithInfo{}, fmt.Errorf("解压多分片数据失败: %v", err)
	}

	// 反序列化
	var data chunkData
	if err := sonic.Unmarshal(decompressedData, &data); err != nil {
		return chunkDataWithInfo{}, fmt.Errorf("反序列化多分片数据失败: %v", err)
	}

	result := chunkDataWithInfo{
		chunkData:    data,
		OriginalSize: firstChunk.Resource.GetOriginalSize(),
		PointCount:   firstChunk.Resource.GetPointCount(),
		MetricCount:  firstChunk.Resource.GetMetricCount(),
	}

	// 缓存
	s.chunkCache.Put(cacheKey, result)
	logger.Info("multi-part chunk cached (key=%s), original_size: %d bytes", cacheKey, result.OriginalSize)

	return result, nil
}

// getChunkDataByIDs 内部方法：获取 chunk 数据，支持多 chunk 分片合并
// 当 chunkIDs 只有一个元素时，等价于 getChunkData
// 当 chunkIDs 有多个元素时，按顺序拼接所有 part 的 compressed_data，然后解压
func (s *ReportHandler) getChunkDataByIDs(ctx context.Context, chunkIDs []string) (chunkDataWithInfo, error) {
	if len(chunkIDs) == 0 {
		return chunkDataWithInfo{}, fmt.Errorf("chunk IDs 为空")
	}

	// 优先从缓存查找（用首个 ID 作为缓存 key）
	cacheKey := chunkIDs[0]
	if cachedData, ok := s.chunkCache.Get(cacheKey); ok {
		logger.Debug("chunk %s hit cache (multi-part key)", cacheKey)
		return cachedData, nil
	}

	// 单个 chunk 直接走简单路径
	if len(chunkIDs) == 1 {
		return s.getChunkData(ctx, chunkIDs[0])
	}

	// 多个 chunk：按顺序读取并拼接 compressed_data
	logger.Info("loading multi-part chunk: %d parts", len(chunkIDs))
	var allCompressedData []byte
	var originalSize int64
	var pointCount int32
	var metricCount int32

	for i, chunkID := range chunkIDs {
		chunk, err := s.reportRepo.GetChunk(ctx, chunkID)
		if err != nil {
			return chunkDataWithInfo{}, fmt.Errorf("获取 chunk part %d/%d 失败 (id=%s): %v", i+1, len(chunkIDs), chunkID, err)
		}
		allCompressedData = append(allCompressedData, chunk.Resource.GetCompressedData()...)
		// 取第一个 part 的元数据（所有 part 的元数据相同）
		if i == 0 {
			originalSize = chunk.Resource.GetOriginalSize()
			pointCount = chunk.Resource.GetPointCount()
			metricCount = chunk.Resource.GetMetricCount()
		}
	}

	logger.Info("multi-part chunk assembled: %d bytes from %d parts", len(allCompressedData), len(chunkIDs))

	// 解压拼接后的数据
	decompressedData, err := utils.Decompress(allCompressedData)
	if err != nil {
		return chunkDataWithInfo{}, fmt.Errorf("解压多分片数据失败: %v", err)
	}

	// 反序列化
	var data chunkData
	if err := sonic.Unmarshal(decompressedData, &data); err != nil {
		return chunkDataWithInfo{}, fmt.Errorf("反序列化多分片数据失败: %v", err)
	}

	result := chunkDataWithInfo{
		chunkData:    data,
		OriginalSize: originalSize,
		PointCount:   pointCount,
		MetricCount:  metricCount,
	}

	// 缓存（用首个 ID 作为 key）
	s.chunkCache.Put(cacheKey, result)
	logger.Info("multi-part chunk cached (key=%s), original_size: %d bytes", cacheKey, originalSize)

	return result, nil
}

