// @route /apis/v1/report/chunk/list [POST]
func (s *ReportHandler) GetReportChunkList(ctx context.Context, req *baseV1.IdRequest) *baseV1.Response {
	reportID := req.GetID()

	// 1. 获取报告
	report, err := s.reportRepo.GetReport(ctx, reportID)
	if err != nil {
		return baseV1.Failed(fmt.Errorf("报告不存在: %v", err), int64(baseV1.BaseErrorCode_NOT_FOUND))
	}

	cases := report.Resource.GetCases()
	if len(cases) == 0 {
		return baseV1.Failed(fmt.Errorf("报告没有用例和数据"), int64(baseV1.BaseErrorCode_NOT_FOUND))
	}

	// 2. 遍历 cases，逐个调用 getChunkDataByIDs 获取数据（自动处理缓存和分片合并）
	chunkDataList := make([]chunkDataWithInfo, 0, len(cases))
	for _, singleCase := range cases {
		chunkIDs := getCaseChunkIDs(singleCase)
		if len(chunkIDs) == 0 {
			continue
		}

		// 调用内部方法获取数据（支持分片合并）
		data, err := s.getChunkDataByIDs(ctx, chunkIDs)
		if err != nil {
			return baseV1.Failed(fmt.Errorf("获取 chunk 数据失败 (chunk_ids=%v): %v", chunkIDs, err), int64(baseV1.BaseErrorCode_INTERNAL_ERROR))
		}

		chunkDataList = append(chunkDataList, data)
	}

	return baseV1.Success(baseV1.WithData(chunkDataList))
}

